<span class="line"><span style="color:#CDD6F4;">        harness</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">load_plugin</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">plugin</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#CBA6F7;">await</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap</span><span style="color:#9399B2;">();</span></span>
