<span class="line"><span style="color:#89B4FA;font-style:italic;">        assert!</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">has_word_count</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;word_count tool should be registered&quot;</span><span style="color:#9399B2;">);</span></span>
